#include <bits/stdc++.h>
#define int long long
using namespace std;
const int mod = 998244353;
const int N = 3 * 1e5 + 10;
const int M = 60;
int n;
int m;
int v[2 * N];
int x[2 * N];
int al[N];
int ct;
int dep[N];
int fa[N][22];
int book[N];
int val[N][M];
void add (int u, int V) {
	v[++ct] = V;
	x[ct] = al[u];
	al[u] = ct;
	return;
}
int mi[M];
void dfs (int u) {
	book[u] = true;
    for (int i = 0; fa[u][i]; i++) {
    	fa[u][i + 1] = fa[fa[u][i]][i];
	}
	for (int i = al[u]; i; i = x[i]) {
		if (book[v[i]]) {
			continue;
		}
		fa[v[i]][0] = u;
		dep[v[i]] = dep[u] + 1;
		for (int j = 1; j <= 50; j++) {
			mi[j] = mi[j - 1] * dep[v[i]] % mod;
		}
		for (int j = 1; j <= 50; j++) {
        	val[v[i]][j] = (mi[j] + val[u][j]) % mod;
		}
        dfs (v[i]);
    }
    return ;
}
int lca (int u, int v) {
	if (dep[u] < dep[v]) {
    	swap (u, v);
	}
	int d = dep[u] - dep[v];
    for (int i = 0; d; d >>= 1, i++) {
		if (d & 1) {
			u=fa[u][i];
		}
	}
	if (u == v) {
		return u;
	}
	for (int i = 20; i >= 0; i--) {
		if (fa[u][i] != fa[v][i]) {
			u = fa[u][i];
			v = fa[v][i];
		}
	}
    return fa[u][0]; 
}
signed main () {
	ios::sync_with_stdio (0);
	cin.tie (0), cout.tie (0);
	cin >> n;
	mi[0] = 1;
    for (int i = 1, u, v; i < n; i++) {
		cin >> u >> v;
		add (u, v);
		add (v, u);
	}
	dfs (1);
	cin >> m;
    for (int i = 1, u, v, k; i <= m; i++) {
    	cin >> u >> v >> k;
		int l = lca (u, v);
        cout << (val[u][k] + val[v][k] + 2 * mod - val[fa[l][0]][k] - val[l][k]) % mod << '\n';
	}
	return 0;
}
